  const userId = String(item);
  const user = USER_DIRECTORY[userId];

  return (
    <span className="osdkRichDropdownLabel">
      <strong>{user?.name ?? userId}</strong>
      {user?.team != null ? (
        <span className="osdkRichDropdownDescription">{user.team}</span>
      ) : null}
    </span>
  );
}

