import { http, passthrough } from "msw";
import { utils, write } from "xlsx-republish";

const SAMPLE_SPREADSHEET: ParsedSpreadsheet = {
  sheets: [
    {
      name: "Employees",
      rows: [
        ["Name", "Department", "Title", "Start Date", "Salary"],
