import {
  PdfViewerSidebar,
  usePdfDocument,
} from "@osdk/react-components/experimental/pdf-viewer";
import type { Meta, StoryObj } from "@storybook/react-vite";
import { fn } from "storybook/test";

const SAMPLE_PDF_URL =
  "https://mozilla.github.io/pdf.js/web/compressed.tracemonkey-pldi-09.pdf";

interface ThumbnailSidebarStoryProps {
  src: string;
  currentPage: number;
  onPageClick: (page: number) => void;
}

function ThumbnailSidebarWrapper({
  src,
  currentPage,
  onPageClick,
}: ThumbnailSidebarStoryProps) {
  const { document, numPages, loading, error } = usePdfDocument(src);

  if (loading) {
    return <div>Loading PDF…</div>;
  }
  if (error != null) {
    return <div>Error loading PDF: {error.message}</div>;
  }
  if (document == null) {
    return null;
  }

  return (
    <div style={{ height: "500px", width: "200px" }}>
      <PdfViewerSidebar
        document={document}
        numPages={numPages}
        currentPage={currentPage}
        onPageClick={onPageClick}
        sidebarMode="thumbnails"
        onSidebarModeChange={() => {}}
      />
    </div>
  );
}

const meta: Meta<ThumbnailSidebarStoryProps> = {
  title:
    "Components/DocumentViewer/Renderers/PdfViewer/Building Blocks/ThumbnailSidebar",
  component: ThumbnailSidebarWrapper,
