    src: {
      description: "PDF source URL (used to load the document)",
      control: "text",
    },
  },
};

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {};

export const ActivePage: Story = {
  args: {
    currentPage: 5,
  },
};

