const Default = () => <div className="object-table-container" style={{ height: "600px" }}>
    <ObjectTable objectType={Employee} columnDefinitions={defaultEmployeeColumns} />
</div>;

const WithObjectSet = () => {
    const client = useOsdkClient();
    const employeeObjectSet = client(Employee).where({
      jobProfile: "Marketing Manager",
    });

    return (
        <div className="object-table-container" style={{ height: "600px" }}>
            <ObjectTable
                columnDefinitions={defaultEmployeeColumns}
                objectType={Employee}
                objectSet={employeeObjectSet} />
        </div>
    );
};

const WithInterfaceType = () => <div className="object-table-container" style={{ height: "600px" }}>
    <ObjectTable objectType={WorkerInterface as unknown as typeof Employee} />
</div>;

const WithDerivedPropertyOrderingAndFilter = () => {
  type RDPs = { managerName: "string" };

  const columnDefinitions: ColumnDefinition<Employee, RDPs>[] = [
    { locator: { type: "property", id: "fullName" } },
    { locator: { type: "property", id: "department" } },
    {
      locator: {
        type: "rdp",
        id: "managerName",
        creator: (baseObjectSet: DerivedProperty.Builder<Employee, false>) =>
          baseObjectSet.pivotTo("lead").selectProperty("fullName"),
      },
      renderHeader: () => "Manager",
      renderCell: (object: Osdk.Instance<Employee>) => {
        if ("managerName" in object) {
          return <span>{object.managerName as string}</span>;
        }
        return <span style={{ color: "#999" }}>No Manager</span>;
      },
    },
  ];

  const filter: WhereClause<Employee, RDPs> = {
    managerName: { $in: ["Ahmed Williams", "Fatima Zhang"] },
  };

  return (
    <div className="object-table-container" style={{ height: "600px" }}>
      <ObjectTable
        objectType={Employee}
        columnDefinitions={columnDefinitions}
        defaultOrderBy={[{ property: "managerName", direction: "asc" }]}
        filter={filter}
      />
    </div>
  );
};

const WithFunctionColumn = () => <div className="object-table-container" style={{ height: "600px" }}>
    <ObjectTable
        objectType={Employee}
        columnDefinitions={[
          { locator: { type: "property", id: "fullName" } },
          { locator: { type: "property", id: "department" } },
          {
            locator: {
              type: "function",
              id: "seniority",
              queryDefinition: getEmployeeSeniority,
              getFunctionParams: (objectSet: ObjectSet<Employee>) =>
                (({
                  employees: objectSet
                }) as never),
              getKey: (object: Osdk.Instance<Employee>) =>
                String(object.$primaryKey),
              getValue: (cellData?: unknown) => cellData,
            },
            renderHeader: () => "Seniority",
            width: 120,
          },
        ] as ColumnDefinition<Employee>[]} />
</div>;

const SingleSelection = () => <div className="object-table-container" style={{ height: "600px" }}>
