        objectType={Employee}
        columnDefinitions={defaultEmployeeColumns}
        selectionMode="single"
        onRowSelectionChanged={fn()} />
</div>;

const MultipleSelection = () => <div className="object-table-container" style={{ height: "600px" }}>
