const CustomColumnWidths = () => <div className="object-table-container" style={{ height: "600px" }}>
    <ObjectTable
        objectType={Employee}
        columnDefinitions={columnDefinitions.map((col, index) => ({
          ...col,
          width: index === 0 ? 250 : index === 1 ? 300 : 150,
        })) as any} />
